using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using Microsoft.Agents.AI;
using Microsoft.Agents.AI.ChatCompletion;

var services = new ServiceCollection();

services.AddLogging(builder => builder.AddConsole().SetMinimumLevel(LogLevel.Information));

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

services.AddChatClient(builder => builder
    .UseOpenAIChatClient("gpt-4o-mini-2024-07-18", apiKey));

var sp = services.BuildServiceProvider();

var chatClient = sp.GetRequiredService<IChatClient>();
var logger = sp.GetRequiredService<ILogger<Program>>();

// Create the research agent with tools
var tools = new ResearchTools();
var agent = new ChatClientAgent(chatClient, "ResearchAgent")
{
    Instructions = """
        You are a research agent. When given a topic, you:
        1. Search the web for relevant information using the search tool.
        2. Take notes on key findings using the note-taking tool.
        3. Perform additional searches to fill knowledge gaps.
        4. Produce a final summary of your research findings.
        Be thorough but concise. Cite your sources.
        """,
    Tools = [.. AIFunctionFactory.Create(tools)]
};

Console.WriteLine("=== Research Agent ===");
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

logger.LogInformation("Researching topic: {Topic}", topic);

var history = new List<ChatMessage>
{
    new(ChatRole.User,
        $"Research the following topic and provide a comprehensive summary: {topic}")
};

var options = new AgentInvokeOptions
{
    MaximumIterations = 10,
};

Console.WriteLine($"\nResearching \"{topic}\"...\n");

await foreach (var message in agent.InvokeStreamingAsync(history, options))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        Console.Write(message.Text);
    }
}

Console.WriteLine("\n\n--- Notes collected during research ---");
foreach (var note in tools.GetNotes())
{
    Console.WriteLine($"  • {note}");
}

Console.WriteLine("\nResearch complete.");

/// <summary>
/// Tools available to the research agent for web searching and note-taking.
/// </summary>
public sealed class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _httpClient = new();

    [Description("Search the web for information on a query. Returns search result snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up")] string query)
    {
        Console.WriteLine($"  [🔍 Searching: \"{query}\"]");

        try
        {
            // Use a public search API (DuckDuckGo instant answer)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var response = await _httpClient.GetStringAsync(url);

            // Parse key fields from the JSON response
            var doc = System.Text.Json.JsonDocument.Parse(response);
            var root = doc.RootElement;

            var results = new List<string>();

            var abstractText = root.GetProperty("AbstractText").GetString();
            if (!string.IsNullOrEmpty(abstractText))
            {
                var source = root.GetProperty("AbstractSource").GetString();
                results.Add($"[{source}] {abstractText}");
            }

            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var item in topics.EnumerateArray().Take(5))
                {
                    if (item.TryGetProperty("Text", out var text))
                    {
                        var snippet = text.GetString();
                        if (!string.IsNullOrEmpty(snippet))
                        {
                            results.Add(snippet);
                        }
                    }
                }
            }

            if (results.Count == 0)
            {
                return $"No detailed results found for '{query}'. Try a more specific search.";
            }

            return string.Join("\n\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Save a research note for later reference. Use this to record key findings.")]
    public string TakeNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  [📝 Note saved: \"{Truncate(note, 60)}\"]");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieve all notes taken so far during research.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes taken yet.";
        }

        return string.Join("\n", _notes.Select((n, i) => $"{i + 1}. {n}"));
    }

    public IReadOnlyList<string> GetNotes() => _notes.AsReadOnly();

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "...";
}

