using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using Microsoft.Agents.AI;

var services = new ServiceCollection();

services.AddLogging(builder => builder.AddConsole().SetMinimumLevel(LogLevel.Information));

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

services.AddChatClient(builder => builder
    .UseOpenAIChatClient("gpt-4o-mini-2024-07-18", apiKey));

var sp = services.BuildServiceProvider();

var chatClient = sp.GetRequiredService<IChatClient>();
var logger = sp.GetRequiredService<ILogger<Program>>();

// Create tools
var researchTools = new ResearchTools();
var tools = AIFunctionFactory.Create(researchTools);

// Configure the agent
var agentOptions = new ChatClientAgentOptions
{
    Name = "ResearchAgent",
    Description = "An agent that researches topics by searching the web and taking notes.",
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
        Tools = [.. tools],
    },
};

var agent = new ChatClientAgent(chatClient, agentOptions,
    loggerFactory: sp.GetRequiredService<ILoggerFactory>());

Console.WriteLine("=== Research Agent ===");
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

logger.LogInformation("Researching topic: {Topic}", topic);
Console.WriteLine($"\nResearching \"{topic}\"...\n");

// Create a session and run the agent
var session = await agent.CreateSessionAsync(conversationId: Guid.NewGuid().ToString());

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
    Tools = [.. tools],
});

var prompt = $"""
    Research the following topic and provide a comprehensive summary: {topic}

    Instructions:
    1. Search the web for relevant information using the SearchWeb tool.
    2. Take notes on key findings using the TakeNote tool.
    3. Perform additional searches to fill knowledge gaps.
    4. After gathering enough information, retrieve your notes with GetAllNotes.
    5. Produce a final summary of your research findings, citing sources.
    """;

await foreach (var update in agent.RunStreamingAsync(prompt, session, runOptions))
{
    if (update.Role == ChatRole.Assistant && !string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine("\n\n--- Notes collected during research ---");
foreach (var note in researchTools.GetNotes())
{
    Console.WriteLine($"  • {note}");
}

Console.WriteLine("\nResearch complete.");

